var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"KNIGHT_NPC_TEMPLE_BOSS","text":{"KOREA":" 저 둘이 부활의 지팡이를 훔친 자들인가?","JPN":" あの二人が復活の杖を盗んだ者たちか？","ENG":"Are these two the ones who stole the Staff of Resurrection?","TWN":"就是他們偷走復活之杖的嗎？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"KNIGHT_NPC_TEMPLE_NULL","text":{"KOREA":" 예. 그렇습니다.","JPN":" はい。そのとおりです。","ENG":"Yes, sir. That is correct.","TWN":"是，就是他們。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"KNIGHT_NPC_TEMPLE_BOSS","text":{"KOREA":" 저런 애송이들이 부활의 지팡이를 훔쳐 달아났다니……","JPN":" あんな若造どもが復活の杖を盗んで逃げたとは……","ENG":"To think that these kids would run off with the Staff of Resurrection...","TWN":"復活之杖竟然被那種小鬼偷走……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"KNIGHT_NPC_TEMPLE_BOSS","text":{"KOREA":" 남쪽 신전의 신전장님이 아니었으면 교단에 면목이 없을 뻔했군.","JPN":" 南方の神殿の神殿長でなかったら、教団の面目が丸潰れになるところだった。","ENG":"If it weren’t for the Head Priestess of the Southern Temple, we would have brought disgrace upon the Order.","TWN":"若非南方神殿的祭司長，教團差點就顏面盡失！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"KNIGHT_NPC_TEMPLE_BOSS","text":{"KOREA":" 시간이 됐군. 호송 마차에 태워라.","JPN":" 時間だな。護送車に乗せろ。","ENG":"It’s time. Load them into the prisoner carriage.","TWN":"時候到了，上馬車吧。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_TEMPLE_BOSS","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":" …….","JPN":" ……","ENG":"...","TWN":"……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":" 저기……. 지금 어디로 가는 거죠?","JPN":" あの……　今どこに向かってるんですか？","ENG":"Um... Where are you taking us?","TWN":"請問……我們要去哪裡？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KNIGHT_NPC_TEMPLE_NULL","text":{"KOREA":" 처형장으로 간다. ","JPN":" 処刑場だ。 ","ENG":"To the execution ground.","TWN":"去刑場。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KNIGHT_NPC_TEMPLE_NULL","text":{"KOREA":" 너희 두 사람은 출정식을 마치는 대로 군중들 앞에서 화형에 처해질 거다.","JPN":" お前ら二人は出征式が終わり次第、群衆の前で火刑に処される予定だ。","ENG":"You two will be burned at the stake in front of the crowd after the ceremony ends.","TWN":"等出征儀式結束後，就會立刻在眾人面前將你們處以火刑。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KNIGHT_NPC_TEMPLE_NULL","text":{"KOREA":" 마왕과의 전쟁 중에 사리사욕을 챙기려는 자들에게 좋은 본보기가 되겠지. ","JPN":" 魔王との戦争の途中、私利私欲をむさぼる者たちのいい見せしめになるだろう。 ","ENG":"It should serve as an example to those who would prioritize their self-interests during a war against the Demon Lord.","TWN":"剛好可以對那些企圖在和魔王的戰爭中謀取私人利益的傢伙，達到殺雞儆猴的效果。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":" 적어도 확인은 해 주세요. 저희 둘 다 신전장이 마왕의 수하들과 함께 있는 모습을…….","JPN":" せめて確認だけはしてください。僕たちは二人とも神殿長が魔王の手下といる姿を……","ENG":"At least look into our claims. The both of us saw the Head Priestess with the minions─","TWN":"拜託你們至少調查一下吧，我們兩個親眼見到祭司長和魔王的手下一起……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"KNIGHT_NPC_TEMPLE_NULL","text":{"KOREA":" 닥쳐라, 네 이놈! 그렇게 두들겨 맞아 놓고 아직까지 그런 헛소리냐!","JPN":" 黙れ！　あれだけ殴られても、まだうわごとを言うか！","ENG":"Shut it you bastard! Are you still spouting that nonsense even after receiving such a beating?!","TWN":"閉嘴！你這傢伙到現在還在胡說八道！是嫌被打得還不夠嗎！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":" 아무런 단서도 나오지 않는다면 처벌은 달게 받겠습니다. ","JPN":" 何の証拠も出なければ甘んじて処罰は受けます。 ","ENG":"If no evidence of our claim is found, I’ll accept my punishment without complaint.","TWN":"若是沒有找到任何線索，那我甘願受罰。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":" 그렇지만 조사도 하지 않고 집행하는 건 너무하지 않나요?","JPN":" でも調査もなく執行するというのは酷すぎませんか？","ENG":"However, isn’t it too unfair to execute us without an investigation?","TWN":"但你們連調查都沒調查就要處決我們，這樣不會太過分嗎？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":" 집어치워, 겁쟁아. 다 끝났어.","JPN":" もう止めて、弱虫。全部終わったの。","ENG":"Give it up, coward. It’s all over for us.","TWN":"算了吧，膽小鬼，都結束了。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":" ……루크레시아.","JPN":" ……ルクレシア。","ENG":"Lucrecia...","TWN":"……露可蕾西亞，"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":" 기운내. 아직 방법이 있을 거야.","JPN":" 元気出して。まだ方法はあるはずだよ。","ENG":"Don’t give up yet. There has to be a way.","TWN":"還不到放棄的時候，一定會有方法的。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":" 무슨 방법? 덜 아프게 죽는 방법?","JPN":" 何の方法？　痛くない死に方？","ENG":"What way? A way to die less painfully?","TWN":"什麼方法？死得輕鬆一點的方法嗎？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":" 그래. 한낱 노예 주제에 희망 따위를 가지니까 이렇게 된 거야.","JPN":" そうよ。ただの奴隷の分際で希望なんか持つからこうなるの。","ENG":"What did I expect? This is what happens when a mere slave dares to have hope in something.","TWN":"都怪我明明是一個小小的奴隸，卻懷抱著不切實際的希望，才會落得這般下場。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":" 얌전히 노예로 살다 뒈지면 될 걸, 왜 할아버지가 하던 헛소리에 한눈을 팔아선…….","JPN":" おとなしく奴隷として生きてくたばればいいのに、お爺さんのうわごとに夢なんか見ちゃって……","ENG":"I should have just lived and died silently as a slave. Why did I allow myself to fall for grandpa’s nonsense...?","TWN":"我應該乖乖當奴隸當到死，幹嘛沒事聽爺爺的胡說八道……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":" ……","JPN":" ……","ENG":"...","TWN":"……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":" 그 인간들 말이 맞아. 나는 뼛속까지 멍청한 노예 계집애야.","JPN":" あいつらの言うことは間違ってないわ。私は根からバカな奴隷の小娘なのよ。","ENG":"They’re right. I’m a dumb slave to the bone.","TWN":"他們說的沒錯，我就是一個蠢到骨子裡的奴隸。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":" 처음부터…… 이 세상에 구원 따위는 없었는데…….","JPN":" 最初から……この世界に救いなんかなかったのに……","ENG":"There never was... Such a thing as salvation in this world...","TWN":"這個世界……根本就沒有救贖……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":" 그렇지 않아. 루크레시아.","JPN":" そんなことないよ。ルクレシア。","ENG":"You’re wrong, Lucrecia.","TWN":"不是的，露可蕾西亞。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L34_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":" 내가 본 너는 한낱 노예도 아니고, 멍청하지도 않았어.","JPN":" 僕が見た君はただの奴隷でもないし、バカでもなかった。","ENG":"The Lucrecia that I’ve seen is not a mere slave, nor is she dumb.","TWN":"你在我眼裡不是奴隸，而且一點也不蠢。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":" 오히려 노예라는 네 운명에 맞서려고 하던 모습이 무척이나 아름다웠다고 생각해.","JPN":" むしろ奴隷という自分の運命に立ち向かおうとする姿がとても美しかったと思う。","ENG":"I thought the way you tried to fight against your fate as a slave was very beautiful.","TWN":"我反而覺得你努力想改變奴隸宿命的樣子很美。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_LAUGH"}}}},{"id":"L36_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":" 나는 태어나서 한 번도, 내 운명에 맞서려고 했던 적이 없으니까.","JPN":" 僕は生まれて一度も、自分の運命に立ち向かおうとしたことがなかったから。","ENG":"After all, I’ve never tried to fight against my fate even once throughout my life.","TWN":"因為我從出生到現在，從沒來有想過要改變宿命。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":" 닥쳐!! 닥쳐, 제발 그만 좀 닥치라고! ","JPN":" 黙れ！！　黙って、お願いだから黙ってよ！ ","ENG":"Shut up! Please, just shut up!","TWN":"閉嘴閉嘴！！拜託你別再說了！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"KNIGHT_NPC_TEMPLE_NULL","text":{"KOREA":" 시끄럽다! 죄인이면 죄인답게 얌전히 있어!","JPN":" うるさい！　罪人は罪人らしくおとなしくしろ！","ENG":"Stop your yapping, the both of you! Shut up and be quiet, criminal scum!","TWN":"安靜一點！身為犯人還在那邊吵吵鬧鬧的！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":" ……","JPN":" ……","ENG":"...","TWN":"……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":" 난 널 두고 도망간 쓰레기야. 그걸로 됐잖아? 어디까지 더 비참하게 만들어야 돼?","JPN":" 私はあんたを見捨てて逃げたクズよ。それでいいでしょ？　どこまで惨めにさせる気なの？","ENG":"I’m the scumbag that ran off by myself and left you behind. That’s all there is, right? How much more miserable do you have to make me feel?","TWN":"我就是扔下你逃走的垃圾，這樣還不夠嗎？你還要把我搞得多悲慘你才高興？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":" 도와 줄게.","JPN":" 助けてあげるよ。","ENG":"Let me help you.","TWN":"我會幫你的。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":" 너……. 갑자기 그게 무슨 소리야? 미치기라도 했어?","JPN":" あんた……　突然何言ってるの？　頭でもおかしくなった？","ENG":"What...? What the hell is that supposed to mean? Are you crazy?","TWN":"你……在說什麼？你在發什麼瘋？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":" 센트럴 팰리스에 오기 전에 알렌이 말했어. ","JPN":" セントラルパレスに来る前にアレンが言ったんだ。 ","ENG":"Before I came to Central Palace, Allen told me this.","TWN":"來聖特羅貝里斯之前艾倫有說過，"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":" 세상에 구원이란 게 없더라도, 누군가는 사람들을 도울 수 있을 거라고.","JPN":" 世界に救いというものが無かったとしても、誰かは人々を救うことができるかもしれないって。","ENG":"Even if there is no such thing as salvation in this world, someone may be able to help people.","TWN":"就算世界上沒有所謂的救贖，或許有那麼一個人可以幫助大家。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":" 도움이 필요하다면 그렇다고 얘기해 줘. ","JPN":" 助けが必要ならそう言って。 ","ENG":"If you need help, please just say so.","TWN":"若你需要幫助，那就告訴我，"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":" 도와 줄게. 루크레시아.","JPN":" 助けてあげるから。ルクレシア。","ENG":"I’ll help you, Lucrecia.","TWN":"我會幫你的，露可蕾西亞。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":" 나는……","JPN":" 私は……","ENG":"I...","TWN":"我……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":" 나는, 더 많은 걸 하고 싶어.","JPN":" 私は、もっと色んなことをしてみたい。","ENG":"I, want to do so many things.","TWN":"我還有很多想做的事，"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":" 예쁜 옷도 사 입고, 일을 해서 돈도 벌고, 예쁜 집을 구해서 닭이랑 병아리도 기르고……","JPN":" キレイな服も着て、仕事してお金も稼いで、キレイな家でニワトリとひよこも飼って……","ENG":"I want to buy pretty clothes, work and make money, buy a nice house and raise chickens...","TWN":"想買漂亮的衣服來穿，想工作賺錢，想有自己的房子可以養雞……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":" 할아버지처럼은…… 살고 싶지 않아. ","JPN":" お爺さんのようには……生きたくない。 ","ENG":"I don’t want to live like... grandpa.","TWN":"我不想……活得跟爺爺一樣。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":" 그렇게 아무렇게나 버려진 쓰레기처럼 죽기는 싫어……!","JPN":" あんな風に、適当に捨てられたゴミのように死にたくはないよ……！","ENG":"I don’t want to die like garbage thrown on the street...!","TWN":"我不想像被隨意丟掉的垃圾般死去……！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":" 그러니까…… 그러니까……","JPN":" だから……だから……","ENG":"So... Please...","TWN":"所以……所以……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":" 도와 줘.","JPN":" 助けて。","ENG":"Help me.","TWN":"幫幫我。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KNIGHT_NPC_TEMPLE_NULL","text":{"KOREA":" 자, 여기서부터는 걸어가야 한다. 마차에서 내려.","JPN":" さあ、ここからは徒歩で行く。馬車から降りろ。","ENG":"All right, we have to walk from here. Get off of the carriage.","TWN":"下車吧，接下來的路必須用走的。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KNIGHT_NPC_TEMPLE_NULL","text":{"KOREA":" 어……?","JPN":" あ……？","ENG":"Huh...?","TWN":"嗯……？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KNIGHT_NPC_TEMPLE_NULL","text":{"KOREA":" 너, 너 이 애송이가…… 어떻게 수갑을……?","JPN":" て、てめえ、この若造……どうやって手錠を……？","ENG":"Y-you scrawny kid... How did you take off the handcuffs...?","TWN":"你…你這小鬼……是怎麼把手銬……？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":" 너…… 마법사였어?","JPN":" あんた……魔法使いだったの？","ENG":"Are you... a mage?","TWN":"你……是魔法師嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":" 아니. 그냥 남들보다 건강한 편이랄까?","JPN":" いや。ただ、他の人より健康だっていうか。","ENG":"No, just healthier than most people, maybe?","TWN":"不是，我只是比別人健康一點而已？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"KNIGHT_NPC_TEMPLE_BOSS","text":{"KOREA":" 이 놈! 마지막까지 도망칠 기회만 노리다니!","JPN":" おのれ！　最後まで逃げる隙を狙っていたか！","ENG":"You bastard! You’re still looking for an opportunity to escape until the end!","TWN":"你這傢伙！死到臨頭還想逃！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_TEMPLE_BOSS","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L24_1","type":"dialog","speaker":"KNIGHT_NPC_TEMPLE_BOSS","text":{"KOREA":" 화형도 네 놈들에게는 과분하다! 이 자리에서 베어 주마!","JPN":" 貴様らには火刑ももったいない！　この場で斬り捨ててやる！","ENG":"You aren’t even worthy of being burned at the stake! I’ll cut the both of you down right now!","TWN":"火刑太便宜你們了！給我斬立決！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_TEMPLE_BOSS","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":" 오래된 검이지만 손질을 자주 해 주셨나 봐요. ","JPN":" 古い剣ですけど、よく手入れがされていますね。 ","ENG":"It’s an old blade, but you must have polished it often.","TWN":"雖然這把劍有點年代，不過似乎還算保養得宜。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":" 잠시 빌리겠습니다. 알렌이 누군가를 구하기 위해서라면 검을 써도 된다고 했거든요.","JPN":" 少しお借りします。アレンが誰かを救うためなら剣を使ってもいいって言ってましたから。","ENG":"Excuse me, I’d like to borrow this for a moment. Allen said that I can use a blade if it’s to save somebody.","TWN":"先借我用一下，艾倫說過，若是因為要救人，那動刀劍是無妨的。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"KNIGHT_NPC_TEMPLE_NULL","text":{"KOREA":" 저, 저 녀석이 단장님의 검을 빼앗았다!","JPN":" あ、あいつが団長の剣を奪ったぞ！","ENG":"Th-the kid took the captain’s sword!","TWN":"他…他搶走了團長的劍！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"KNIGHT_NPC_TEMPLE_NULL","text":{"KOREA":" 죽여도 상관없어! 도망치기 전에 제압해라!","JPN":" 殺しても構わない！　逃げる前に押さえろ！","ENG":"You have permission to kill them! Take them down before they escape!","TWN":"不准讓人給逃了！必要時殺無赦！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":" 어, 어서 내 수갑도 풀어 줘! ","JPN":" は、早く私の手錠も外して！ ","ENG":"T-take these off of my hands too!","TWN":"快…快幫我解開手銬！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":" 아. 미안. 생각해 보니까 풀어 준 다음에 싸워도 되겠네.","JPN":" あ。ごめん。考えてみたら外した後に戦ってもよかったね。","ENG":"Oh, sorry. Now that I think of it, I can fight after I set you free too.","TWN":"啊，抱歉，應該先幫你解開手銬再對付他們的。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":" 사람이 저렇게 많은데 어떻게 싸워! 도망가야 돼!","JPN":" あんな大勢とどうやって戦うっていうの！　逃げなきゃ！","ENG":"We can’t fight them! There are too many! We have to escape!","TWN":"他們人多勢眾，你拿什麼跟人家打，快逃吧！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_SURPRISE"}}}},{"id":"L40_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":" 그러면 안 돼. 여기서 도망쳐도 너는 평생 노예이고 도망자 신세로 살아야 할 거야.","JPN":" それはダメだよ。ここから逃げても君は一生奴隷で、逃亡者の人生を生きることになる。","ENG":"No, we can’t. Even if you escape from here, you’ll have to live the rest of your days as a slave and a fugitive.","TWN":"那可不行，若是現在逃跑的話，那你就會一輩子都是奴隸，而且還必須以通緝犯的身分活下去。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":" 하지만……","JPN":" でも……","ENG":"But...","TWN":"可是……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":" 기다려. 루크레시아.","JPN":" 待っていて。ルクレシア。","ENG":"Wait here, Lucrecia.","TWN":"你等我，露可蕾西亞。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_LAUGH"}}}},{"id":"L43_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":" 내가 너를 구원해 줄게.","JPN":" 僕が君を救ってあげるよ。","ENG":"I'll bring you salvation.","TWN":"我會救你的。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":" 참으로 담대하구나, 소년. 태도로 보아 황혼을 앞두고 온 것은 나름의 계략인가.","JPN":" なんて大胆なんだ。態度から察するに黄昏の直前に来たのは策があってのことだろう。","ENG":"I applaud your boldness, boy. Judging by your attitude, participating just before twilight seems to be a part of your plan.","TWN":"勇氣可嘉，看你的樣子，是刻意挑在太陽快要下山的時候嗎？"},"stage":{"bg":"COLOSSEUM","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":" 부디 그 용맹이 객기가 아니길 바라마.","JPN":" その勇猛が虚勢ではないことを願おう。","ENG":"I hope that your courage is not mere bravado.","TWN":"希望不是逞匹夫之勇。"},"stage":{"bg":"COLOSSEUM","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":" 고하라! 도전자로서 경기장에 나선 그대의 이름은 무엇인가? ","JPN":" 告げよ！　挑戦者として競技場に出たそなたの名前を！ ","ENG":"See here! Challenger of this arena, what is thy name?","TWN":"場上的挑戰者，報上名來！"},"stage":{"bg":"COLOSSEUM","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":" ……레이. 평민이기에 성은 없습니다.","JPN":" ……レイ。平民なので名字はありません。","ENG":"...Ray. As I am a commoner, I have no family name.","TWN":"……雷伊，我是平民，所以沒有姓氏。"},"stage":{"bg":"COLOSSEUM","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":" 멈춰, 레이! 저 분은 황태자 전하시다!","JPN":" 止まれ、レイ！　あの方は皇太子殿下だぞ！","ENG":"Stop, Ray! He is the Crown Prince!","TWN":"住手，雷伊！這位是皇太子殿下！"},"stage":{"bg":"COLOSSEUM","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":" 구원자의 자격을 걸고, 전하께 도전하겠습니다.","JPN":" 救世主の資格をかけて、殿下に挑みます。","ENG":"I challenge you for the title of the Savior, Your Highness.","TWN":"我要賭上救贖者的資格，挑戰殿下。"},"stage":{"bg":"COLOSSEUM","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":" 너, 너…… 지금 자기가 무슨 말을 하는지 알고는 있어?","JPN":" あ、あんた……自分が何を言ってるのかわかってんの？","ENG":"A-are you aware of what you are saying?","TWN":"你……你知道你在說什麼嗎？"},"stage":{"bg":"COLOSSEUM","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":" 응. 황태자 전하께 도전하는 거야.","JPN":" うん。皇太子殿下に挑むんだ。","ENG":"Yup. I’m challenging the Crown Prince.","TWN":"知道，我要挑戰皇太子殿下。"},"stage":{"bg":"COLOSSEUM","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":" 그러고 보니, 네 앞에서 이름은 처음 말한 것 같네.","JPN":" そういえば、君の前で名前を言うのは初めてだったかな。","ENG":"Speaking of which, I think this is the first time that I said my name in front of you.","TWN":"話說回來，這好像是我第一次在你面前說出自己的名字呢。"},"stage":{"bg":"COLOSSEUM","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":" …….","JPN":" ……","ENG":"...","TWN":"……"},"stage":{"bg":"COLOSSEUM","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PRIESTESS_NPC_SOUTH_NULL","text":{"KOREA":" 저것들은…… 저것들은 하수도에서 잡아 온 도둑들 아닌가? ","JPN":" あれは……あれは下水道で捕まえた泥棒ではないか？ ","ENG":"Those two... Aren’t they the thieves we captured in the sewers?","TWN":"他們……他們不是我們從下水道抓回來的小偷嗎？"},"stage":{"bg":"COLOSSEUM","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_SOUTH_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PRIESTESS_NPC_SOUTH_NULL","text":{"KOREA":" 젠장, 말도 안 돼……! 대신전의 기사들은 뭘 한 거지?","JPN":" そんなバカな……！　大神殿の騎士は何をしているの？","ENG":"Damn it, that’s impossible...! What have the knights of the Great Temple done?","TWN":"該死，怎麼會這樣……！大神殿的騎士是幹什麼吃的！"},"stage":{"bg":"COLOSSEUM","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_SOUTH_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":" 그 당당함, 출정식의 마지막을 장식하기에 부족하지 않은 태도로구나.","JPN":" その堂々とした姿、出征式の最後を飾るにふさわしい態度だ。","ENG":"That boldness... It’s exactly the kind of attitude that we need to wrap up the ceremony.","TWN":"你那股泰然自若的自信，很適合拿來替出征儀式畫下完美的句點。"},"stage":{"bg":"COLOSSEUM","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":" 좋다, 소년! 최후의 도전자에 걸맞은 실력을 보여 주길 바라마!","JPN":" よかろう、少年！　最後の挑戦者としてふさわしい実力を見せてくれ！","ENG":"Very well, boy! I hope you display the ability worthy of the final challenger!","TWN":"來吧，少年！希望你拿出最後的挑戰者該有的實力來！"},"stage":{"bg":"COLOSSEUM","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"}]`);export{e as default};